if (running.has(slug)) {
  console.log('[workshop] Already running a step for ' + slug);
  return;
}

// Clone the target codex to a temp directory so the agent runs from within it.
// This ensures all paths the agent discovers are relative to the codex root,
// which matches the worktree structure the implementing anima will work in.
const meta = readMeta(slug);
const codexName = meta.codex;
if (!codexName) {
  console.error('[workshop] No codex set for ' + slug + ' — cannot run pipeline');
  sendSSE(slug, 'status', { step, state: 'failed', error: 'no codex set' });
  return;
}

let cloneDir: string;
try {
  cloneDir = cloneCodex(codexName, meta.sessions?.reader ?? meta.sessionId);
} catch (err: any) {
  console.error('[workshop] Clone failed for ' + codexName + ': ' + err.message);
  sendSSE(slug, 'status', { step, state: 'failed', error: 'clone failed: ' + err.message });
  return;
}

// Shuttle planning inputs into the clone before launching the agent
copyPlanningInputs(slug, cloneDir, step);

const promptPath = path.join(PROJECT_ROOT, 'bin', 'plan-prompts', 'planner.md');

const cliArgs = [
  '--print', '-',
  '--system-prompt-file', promptPath,
  '--model', model,
  '--tools', 'Read,Glob,Grep,Write',
  '--setting-sources', 'user',
  '--permission-mode', 'acceptEdits',
  '--max-budget-usd', step === 'analyst' ? '15' : step === 'writer' ? '5' : '3',
  ...args,
];

console.log('[workshop] Starting ' + step + ' for ' + slug + ' (cwd=' + cloneDir + ')');

const proc = spawn('claude', cliArgs, {
  cwd: cloneDir,
  stdio: ['pipe', 'pipe', 'pipe'],
});

// Send prompt via stdin to avoid arg-length limits and dash-prefix parsing issues.
// Prepend the absolute working directory so the agent doesn't have to guess paths
// when using the Write tool (which requires absolute paths). Without this, agents
// confabulate paths like /workspace/ or /app/ and burn tokens on permission errors.
const groundedPrompt = 'Your working directory is: ' + cloneDir + '\n\n' + prompt;
proc.stdin!.write(groundedPrompt);
proc.stdin!.end();

const pipeline: PipelineProcess = {
  step,
  proc,
  log: [],
  startTime: Date.now(),
  tokenCount: 0,
};

running.set(slug, pipeline);
sendSSE(slug, 'status', { step, state: 'running' });

const appendLog = (line: string) => {
  pipeline.log.push(line);
  // Keep last 500 lines
  if (pipeline.log.length > 500) pipeline.log.shift();
  sendSSE(slug, 'log', { line });
};

let stdoutBuf = '';
proc.stdout!.on('data', (chunk: Buffer) => {
  stdoutBuf += chunk.toString();
  const lines = stdoutBuf.split('\n');
  stdoutBuf = lines.pop() ?? '';
  for (const line of lines) {
    appendLog(line);
  }
});

let stderrBuf = '';
proc.stderr!.on('data', (chunk: Buffer) => {
  stderrBuf += chunk.toString();
  const lines = stderrBuf.split('\n');
  stderrBuf = lines.pop() ?? '';
  for (const line of lines) {
    appendLog('[stderr] ' + line);
  }
});

proc.on('close', (code) => {
  if (stdoutBuf) appendLog(stdoutBuf);
  if (stderrBuf) appendLog('[stderr] ' + stderrBuf);
  running.delete(slug);
  const elapsed = Math.floor((Date.now() - pipeline.startTime) / 1000);
  console.log('[workshop] ' + step + ' for ' + slug + ' finished (code=' + code + ', ' + elapsed + 's)');
  sendSSE(slug, 'status', { step, state: code === 0 ? 'complete' : 'failed', elapsed, code });

  // Copy session transcript snapshot for this step.
  // All pipeline steps share a single session (--resume, no --fork-session),
  // so the same JSONL file grows across steps. We save a snapshot after each
  // step with a step prefix (e.g., reader-X.jsonl, analyst-X.jsonl).
  // Cost computation uses UUID-based dedup to attribute incremental costs.
  //
  // Only copy the transcript for the session ID this step actually used —
  // the Claude projects dir may contain stale JSONL files from prior runs.
  try {
    const projectKey = cloneDir.replace(/\//g, '-');
    const claudeProjectDir = path.join(os.homedir(), '.claude', 'projects', projectKey);
    if (fs.existsSync(claudeProjectDir)) {
      // Extract the session ID this step used from the CLI args
      const sidIdx = cliArgs.indexOf('--session-id');
      const resumeIdx = cliArgs.indexOf('--resume');
      const activeSessionId = sidIdx !== -1 ? cliArgs[sidIdx + 1]
        : resumeIdx !== -1 ? cliArgs[resumeIdx + 1]
        : null;

      if (activeSessionId) {
        const transcriptDir = path.join(SPECS_DIR, slug, 'planner-transcripts');
        fs.mkdirSync(transcriptDir, { recursive: true });
        const src = path.join(claudeProjectDir, activeSessionId + '.jsonl');
        if (fs.existsSync(src)) {
          const dest = path.join(transcriptDir, step + '-' + activeSessionId + '.jsonl');
          fs.copyFileSync(src, dest);

          // Record this step's session ID in meta
          const updatedMeta = readMeta(slug);
          if (!updatedMeta.sessions) updatedMeta.sessions = {};
          updatedMeta.sessions[step] = activeSessionId;
          writeMeta(slug, updatedMeta);
          console.log('[workshop] Saved transcript for ' + step + '/' + slug + ' (session ' + activeSessionId + ')');
        } else {
          console.warn('[workshop] No transcript found for session ' + activeSessionId);
        }
      }
    }
  } catch (err: any) {
    console.warn('[workshop] Failed to copy transcripts: ' + err.message);
  }

  // Shuttle planning outputs back to the specs dir before cleanup
  try {
    copyPlanningOutputs(slug, cloneDir, step);
  } catch (err: any) {
    console.warn('[workshop] Failed to copy planning outputs: ' + err.message);
  }

