1	/**
2	 * decision-review clockwork engine.
3	 *
4	 * Two-pass engine:
5	 *
6	 * First run (plan status 'analyzing'):
7	 *   - Maps decisions to ChoiceQuestionSpec and scope items to BooleanQuestionSpec.
8	 *   - Creates an InputRequestDoc in spider/input-requests.
9	 *   - Blocks with 'patron-input' block type.
10	 *   - If no decisions and no scope items, completes immediately.
11	 *
12	 * Re-run (plan status 'reviewing'):
13	 *   - Reads the completed InputRequestDoc.
14	 *   - Reconciles answers back into the PlanDoc.
15	 *   - Yields a human-readable decisionSummary markdown string.
16	 */
17	
18	import { guild, generateId } from '@shardworks/nexus-core';
19	import type { EngineDesign, EngineRunContext, EngineRunResult } from '@shardworks/fabricator-apparatus';
20	import type { Book } from '@shardworks/stacks-apparatus';
21	import type { StacksApi } from '@shardworks/stacks-apparatus';
22	import type { ClerkApi } from '@shardworks/clerk-apparatus';
23	import type {
24	  InputRequestDoc,
25	  ChoiceQuestionSpec,
26	  BooleanQuestionSpec,
27	  AnswerValue,
28	  ChoiceAnswer,
29	} from '@shardworks/spider-apparatus';
30	import type { PlanDoc, Decision, ScopeItem } from '../types.ts';
31	
32	// ── Helpers ──────────────────────────────────────────────────────────
33	
34	function composeDetails(context?: string, rationale?: string): string | undefined {
35	  if (context && rationale) {
36	    return `${context}\n\nRecommendation rationale: ${rationale}`;
37	  }
38	  if (context) return context;
39	  if (rationale) return `Recommendation rationale: ${rationale}`;
40	  return undefined;
41	}
42	
43	function buildDecisionSummary(decisions: Decision[], scope: ScopeItem[]): string {
44	  const parts: string[] = [];
45	
46	  if (decisions.length > 0) {
47	    parts.push('## Decisions');
48	    parts.push('');
49	    for (const decision of decisions) {
50	      parts.push(`### ${decision.id}: ${decision.question}`);
51	      const selectedKey = decision.selected ?? decision.recommendation;
52	      if (selectedKey && decision.options[selectedKey]) {
53	        parts.push(`**Selected:** ${decision.options[selectedKey]}`);
54	      } else if (selectedKey) {
55	        parts.push(`**Selected:** ${selectedKey}`);
56	      }
57	      if (decision.patronOverride) {
58	        parts.push(`**Patron override:** ${decision.patronOverride}`);
59	      }
60	      parts.push('');
61	    }
62	  }
63	
64	  if (scope.length > 0) {
65	    parts.push('## Scope');
66	    parts.push('');
67	    for (const item of scope) {
68	      const check = item.included ? '[x]' : '[ ]';
69	      const suffix = item.included ? '' : ' (excluded)';
70	      parts.push(`- ${check} ${item.id}: ${item.description}${suffix}`);
71	    }
72	  }
73	
74	  return parts.join('\n').trim();
75	}
76	
77	// ── Engine factory ───────────────────────────────────────────────────
78	
79	export function createDecisionReviewEngine(getPlansBook: () => Book<PlanDoc>): EngineDesign {
80	  return {
81	    id: 'astrolabe.decision-review',
82	
83	    async run(
84	      givens: Record<string, unknown>,
85	      context: EngineRunContext,
86	    ): Promise<EngineRunResult> {
87	      const planId = givens.planId as string;
88	      const book = getPlansBook();
89	
90	      const plan = await book.get(planId);
91	      if (!plan) {
92	        throw new Error(`Plan "${planId}" not found.`);
93	      }
94	
95	      // ── First run: status === 'analyzing' ─────────────────────────
96	
97	      if (plan.status === 'analyzing') {
98	        const decisions = plan.decisions ?? [];
99	        const scopeItems = plan.scope ?? [];
100	
101	        // Fast-path: no decisions and no scope
102	        if (decisions.length === 0 && scopeItems.length === 0) {
103	          await book.patch(planId, {
104	            status: 'writing',
105	            updatedAt: new Date().toISOString(),
106	          });
107	          return {
108	            status: 'completed',
109	            yields: { decisionSummary: '' },
110	          };
111	        }
112	
113	        // Build questions
114	        const questions: Record<string, ChoiceQuestionSpec | BooleanQuestionSpec> = {};
115	        const answers: Record<string, AnswerValue> = {};
116	
117	        for (const decision of decisions) {
118	          const choiceSpec: ChoiceQuestionSpec = {
119	            type: 'choice',
120	            label: decision.question,
121	            details: composeDetails(decision.context, decision.rationale),
122	            options: decision.options,
123	            allowCustom: true,
124	          };
125	          questions[decision.id] = choiceSpec;
126	
127	          if (decision.recommendation) {
128	            answers[decision.id] = { selected: decision.recommendation } as ChoiceAnswer;
129	          }
130	        }
131	
132	        for (const item of scopeItems) {
133	          const boolSpec: BooleanQuestionSpec = {
134	            type: 'boolean',
135	            label: item.description,
