1	/**
2	 * Astrolabe tool tests.
3	 *
4	 * Tests plan-show, plan-list, and the five write tools using an in-memory
5	 * Stacks backend and a minimal fake guild.
6	 */
7	
8	import { describe, it, beforeEach, afterEach } from 'node:test';
9	import assert from 'node:assert/strict';
10	
11	import { setGuild, clearGuild } from '@shardworks/nexus-core';
12	import type { Guild, GuildConfig, StartupContext } from '@shardworks/nexus-core';
