15	import type { StacksApi } from '@shardworks/stacks-apparatus';
16	
17	import { createAstrolabe } from './astrolabe.ts';
18	import type { AstrolabeApi } from './types.ts';
19	import type { PlanDoc } from './types.ts';
20	
21	// ── Test harness ─────────────────────────────────────────────────────
22	
23	let api: AstrolabeApi;
24	let plansBook: ReturnType<StacksApi['book']>;
25	let memBackend: MemoryBackend;
26	
27	function buildStartupCtx(): StartupContext {
28	  return {
29	    on() {},
30	    kits() { return []; },
31	  };
32	}
33	
34	function setup() {
35	  memBackend = new MemoryBackend();
36	  const stacksPlugin = createStacksApparatus(memBackend);
37	  const astrolabePlugin = createAstrolabe();
38	
39	  const apparatusMap = new Map<string, unknown>();
40	
41	  const fakeGuildConfig: GuildConfig = {
42	    name: 'test-guild',
43	    nexus: '0.0.0',
44	    plugins: [],
45	    settings: { model: 'sonnet' },
46	  };
47	
48	  const fakeGuild: Guild = {
49	    home: '/tmp/fake-guild',
50	    apparatus<T>(name: string): T {
51	      const a = apparatusMap.get(name);
52	      if (!a) throw new Error(`Apparatus "${name}" not installed`);
53	      return a as T;
54	    },
55	    config<T>(_pluginId: string): T { return {} as T; },
56	    writeConfig() {},
57	    guildConfig() { return fakeGuildConfig; },
58	    kits: () => [],
59	    apparatuses: () => [],
60	    failedPlugins: () => [],
61	    startupWarnings() { return []; },
62	  };
63	
64	  setGuild(fakeGuild);
65	
66	  // Start stacks
67	  const stacksApparatus = (stacksPlugin as {
68	    apparatus: { start: (ctx: StartupContext) => void; provides: unknown };
69	  }).apparatus;
70	  stacksApparatus.start(buildStartupCtx());
71	  const stacks = stacksApparatus.provides as StacksApi;
72	  apparatusMap.set('stacks', stacks);
73	
74	  // Ensure books exist
75	  memBackend.ensureBook({ ownerId: 'astrolabe', book: 'plans' }, {
76	    indexes: ['status', 'codex', 'createdAt'],
77	  });
78	
79	  // Start astrolabe
80	  const astrolabeApparatus = (astrolabePlugin as {
81	    apparatus: { start: (ctx: StartupContext) => void; provides: unknown };
82	  }).apparatus;
83	  astrolabeApparatus.start(buildStartupCtx());
84	  api = astrolabeApparatus.provides as AstrolabeApi;
85	
86	  // Also set api in apparatus map so tools can resolve it
87	  apparatusMap.set('astrolabe', api);
88	
89	  // Get book reference for direct plan creation
90	  plansBook = stacks.book<PlanDoc>('astrolabe', 'plans');
91	}
92	
93	function makePlan(overrides: Partial<PlanDoc> = {}): PlanDoc {
94	  const now = new Date().toISOString();
95	  return {
96	    id: `w-test-${Math.random().toString(36).slice(2)}`,
97	    codex: 'test-codex',
98	    status: 'reading',
99	    createdAt: now,
100	    updatedAt: now,
101	    ...overrides,
102	  };
103	}
104	
105	// ── Tests ─────────────────────────────────────────────────────────────
106	
107	describe('Astrolabe tools', () => {
108	  beforeEach(() => { setup(); });
109	  afterEach(() => { clearGuild(); });
110	
111	  // ── plan-show ──────────────────────────────────────────────────────
112	
113	  describe('plan-show (via api.show)', () => {
114	    it('returns the full PlanDoc when it exists', async () => {
115	      const plan = makePlan({ status: 'reading', inventory: 'some inventory' });
116	      await plansBook.put(plan);
117	
118	      const result = await api.show(plan.id);
119	      assert.equal(result.id, plan.id);
120	      assert.equal(result.codex, plan.codex);
121	      assert.equal(result.status, 'reading');
122	      assert.equal(result.inventory, 'some inventory');
123	    });
124	
125	    it('throws when plan not found', async () => {
126	      await assert.rejects(
127	        () => api.show('nonexistent-plan'),
128	        (err: Error) => {
129	          assert.ok(err.message.includes('not found'));
130	          return true;
131	        },
132	      );
133	    });
134	  });
135	
136	  // ── plan-list ──────────────────────────────────────────────────────
137	
138	  describe('plan-list (via api.list)', () => {
139	    it('returns empty array when no plans exist', async () => {
140	      const result = await api.list();
141	      assert.deepEqual(result, []);
142	    });
143	
144	    it('returns all plans ordered by createdAt descending', async () => {
145	      const p1 = makePlan({ id: 'plan-1', createdAt: '2024-01-01T00:00:00.000Z', updatedAt: '2024-01-01T00:00:00.000Z' });
146	      const p2 = makePlan({ id: 'plan-2', createdAt: '2024-01-03T00:00:00.000Z', updatedAt: '2024-01-03T00:00:00.000Z' });
147	      const p3 = makePlan({ id: 'plan-3', createdAt: '2024-01-02T00:00:00.000Z', updatedAt: '2024-01-02T00:00:00.000Z' });
148	      await plansBook.put(p1);
149	      await plansBook.put(p2);
150	      await plansBook.put(p3);
151	
152	      const result = await api.list();
153	      assert.equal(result.length, 3);
154	      assert.equal(result[0].id, 'plan-2');
155	      assert.equal(result[1].id, 'plan-3');
156	      assert.equal(result[2].id, 'plan-1');
157	    });
